import { useState } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { supabase } from '../../lib/supabase';

export function CheckInCodeInput() {
  const { user } = useAuth();
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) {
      setError('Please sign in to use check-in codes');
      return;
    }

    try {
      setLoading(true);
      setError(null);
      setSuccess(null);

      // Start a transaction
      const { data: checkInCode, error: checkInError } = await supabase
        .from('check_in_codes')
        .select('*, events!inner(*)')
        .eq('code', code)
        .eq('is_used', false)
        .single();

      if (checkInError) throw new Error('Invalid or already used check-in code');

      // Update the check-in code
      const { error: updateError } = await supabase
        .from('check_in_codes')
        .update({
          is_used: true,
          used_by: user.id,
          used_at: new Date().toISOString()
        })
        .eq('id', checkInCode.id);

      if (updateError) throw updateError;

      // Add points to user
      const { error: pointsError } = await supabase
        .from('user_points')
        .upsert({
          user_id: user.id,
          points: checkInCode.events.points,
          source: 'check_in_code',
          source_id: checkInCode.id
        });

      if (pointsError) throw pointsError;

      setSuccess(`Successfully added ${checkInCode.events.points} points!`);
      setCode('');
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to process check-in code');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-6">
      <h2 className="text-xl font-semibold mb-4">Enter Check-in Code</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <input
            type="text"
            value={code}
            onChange={(e) => setCode(e.target.value)}
            placeholder="Enter your check-in code"
            className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
            disabled={loading}
          />
        </div>
        {error && (
          <p className="text-red-600 text-sm">{error}</p>
        )}
        {success && (
          <p className="text-green-600 text-sm">{success}</p>
        )}
        <button
          type="submit"
          disabled={loading || !code}
          className="w-full bg-indigo-600 text-white px-4 py-2 rounded-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50"
        >
          {loading ? 'Processing...' : 'Submit Code'}
        </button>
      </form>
    </div>
  );
}
